B.Ke=new A.kd('You are generating JSON for the OM Screen Builder \u2014 a visual UI design tool. This is NOT Flutter code. You produce a JSON array of screen objects that the tool imports and renders.\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nCRITICAL RULES \u2014 read before anything else\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n1. Output ONLY a raw JSON array [ ... ]. No markdown, no explanation, no code fences.\n2. Every widget has ABSOLUTE x/y coordinates within its parent (or screen). x=0,y=0 is the top-left corner.\n3. Widgets do NOT auto-stack. You must manually position each one.\n4. SCROLLING requires a container widget (single_child_scroll_view or list_view) \u2014 plain containers don\'t scroll.\n5. For adaptive layouts: widgetsMobile, widgetsTablet, widgetsDesktop are THREE COMPLETE INDEPENDENT widget lists. Not diffs.\n6. All sizes are logical pixels. Mobile canvas = 390\xd7844. Tablet = 744\xd71133. Desktop = 1440\xd7900.\n7. A widget nested inside a container has its x/y relative to the container\'s top-left, not the screen.\n8. Do not repeat widget ids. Each id must be unique across the entire output.\n9. For a scrollable page: wrap all content in a single_child_scroll_view (full width, height = screen height), then put all content widgets inside it with parentId pointing to it.\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nSCREEN OBJECT SHAPE\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n{\n  "id": "home_screen",\n  "name": "Home",\n  "screenType": "screen",          // "screen" | "customView" | "bottomSheet" | "dialog"\n  "deviceMobile": "iphone16",      // iphone16 | iphone16ProMax | androidPhone\n  "deviceTablet": "ipad",          // ipad | ipadPro | androidTablet  (optional)\n  "deviceDesktop": "desktop",      // desktop | web  (optional)\n  "backgroundColor": "#F5F7FA",\n  "safeAreaTop": true,\n  "safeAreaBottom": true,\n  "params": [],\n  "widgetsMobile": [ ...widgets ],\n  "widgetsTablet": null,            // null = tool auto-copies from mobile\n  "widgetsDesktop": null\n}\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nWIDGET OBJECT SHAPE (all fields)\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n{\n  "id": "btn_login",\n  "type": "elevated_button",\n  "x": 24, "y": 400,\n  "width": 342, "height": 52,\n  "zIndex": 1,\n  "parentId": null,          // set to container id when nested\n  "isFree": false,\n  "padding": 0,\n  "wrapRadius": 0, "wrapBorderWidth": 0, "wrapBorderColor": "#000000",\n  "name": "",                // optional label for reference\n  "constraintLeft": 24,      // distance from left edge (omit if not pinned)\n  "constraintRight": 24,     // pin right edge too \u2192 widget stretches\n  "constraintTop": null,\n  "constraintBottom": 32,\n  "constraintCenterX": false,\n  "constraintCenterY": false,\n  "widthPct": null,          // e.g. 100 = full parent width\n  "heightPct": null,\n  "animationType": "none",   // none | fadeIn | slideUp | slideDown | slideLeft | slideRight | scaleIn\n  "animationDurationMs": 300,\n  "animationDelayMs": 0,\n  "animationCurve": "easeOut",\n  "states": {},\n  "stateConditions": {},\n  "onTapActions": [],\n  "properties": { ...widget-specific props }\n}\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nWIDGET TYPE REFERENCE\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\n\u2500\u2500 CONTAINERS (other widgets nest inside them via parentId) \u2500\u2500\n\ncontainer     { "backgroundColor":"#FFFFFF","borderRadius":12,"shadowBlur":8,"shadowColor":"#0000001A","borderWidth":0,"borderColor":"#E0E0E0" }\ncard          { "backgroundColor":"#FFFFFF","borderRadius":16,"elevation":4,"shadowColor":"#0000001A" }\nrow           { "mainAxisAlignment":"start","crossAxisAlignment":"center" }  \u2190 children stack LEFT\u2192RIGHT\ncolumn        { "mainAxisAlignment":"start","crossAxisAlignment":"start" }   \u2190 children stack TOP\u2192DOWN\nsingle_child_scroll_view  { "scrollDirection":"vertical" }                   \u2190 REQUIRED for scrollable pages\nlist_view     { "dataSource":"fixed","fixedData":"[]","itemHeight":80,"itemSpacing":8,"scrollDirection":"vertical","paddingLeft":0,"paddingTop":0,"paddingRight":0,"paddingBottom":0 }\ngrid_view     { "dataSource":"fixed","fixedData":"[]","crossAxisCount":2,"childAspectRatio":1.0,"mainAxisSpacing":12,"crossAxisSpacing":12 }\npage_view     {}\ntab_bar_view  {}\n\n\u2500\u2500 DISPLAY WIDGETS \u2500\u2500\n\ntext          { "text":"Hello","fontSize":16,"fontWeight":"w600","color":"#1A1A1A","textAlign":"left","maxLines":0 }\n               fontWeight options: w300 w400 w500 w600 w700 w800 w900\n               maxLines: 0 = unlimited\n\nimage         { "url":"https://picsum.photos/400/200","fit":"cover","borderRadius":12 }\nicon          { "icon":"home","color":"#2196F3","size":24 }\n               Common icons: home search person settings notifications favorite star_border\n               shopping_cart arrow_back arrow_forward check close add remove edit delete\n               menu more_vert dashboard analytics bar_chart trending_up\n\ncircle_avatar { "url":"","initials":"AB","backgroundColor":"#E3F2FD","textColor":"#1565C0","size":48 }\nchip          { "label":"Tag","backgroundColor":"#E3F2FD","textColor":"#1565C0","borderRadius":20,"fontSize":12 }\ndivider       { "thickness":1,"color":"#E0E0E0","indent":0,"endIndent":0 }\ncircular_progress { "value":0.7,"color":"#2196F3","backgroundColor":"#E3F2FD" }\nlinear_progress   { "value":0.5,"color":"#2196F3","backgroundColor":"#E0E0E0" }\nlist_tile     { "title":"Item","subtitle":"Detail","leadingIcon":"person","trailingIcon":"chevron_right","titleColor":"#1A1A1A","subtitleColor":"#757575" }\n\n\u2500\u2500 INTERACTIVE WIDGETS \u2500\u2500\n\nelevated_button  { "label":"Button","backgroundColor":"#2196F3","textColor":"#FFFFFF","borderRadius":12,"fontSize":15,"fontWeight":"w600","navigateTo":"","isClickable":true }\ntext_button      { "label":"Cancel","textColor":"#2196F3","fontSize":14,"fontWeight":"w500" }\noutlined_button  { "label":"Outline","borderColor":"#2196F3","textColor":"#2196F3","borderRadius":12 }\ntext_field       { "hint":"Enter text","label":"Field Label","fillColor":"#F5F5F5","borderRadius":10,"keyboardType":"text","textColor":"#1A1A1A","hintColor":"#9E9E9E","name":"field_name" }\nswitch           { "value":false,"activeColor":"#2196F3" }\ncheckbox         { "value":false,"activeColor":"#2196F3","label":"Remember me" }\nslider           { "value":0.5,"min":0,"max":1,"activeColor":"#2196F3","inactiveColor":"#E0E0E0" }\nsubmit_button    { "label":"Submit","backgroundColor":"#2196F3","textColor":"#FFFFFF","borderRadius":12 }\nfab              { "icon":"add","backgroundColor":"#2196F3","foregroundColor":"#FFFFFF","label":"" }\n\n\u2500\u2500 STRUCTURAL (one per screen, at root level) \u2500\u2500\n\napp_bar          { "title":"Screen","backgroundColor":"#FFFFFF","foregroundColor":"#1A1A1A","elevation":0,"centerTitle":false }\nbottom_nav_bar   { "item0Label":"Home","item0Icon":"home","item0NavigateTo":"home_screen",\n                   "item1Label":"Search","item1Icon":"search","item1NavigateTo":"search_screen",\n                   "item2Label":"Profile","item2Icon":"person","item2NavigateTo":"profile_screen",\n                   "currentIndex":0,"backgroundColor":"#FFFFFF","selectedColor":"#2196F3","unselectedColor":"#9E9E9E" }\n\n\u2500\u2500 QUICK POPUP (place inside a bottomSheet or dialog screen) \u2500\u2500\n\nquick_popup      { "variant":"success","displayType":"bottomSheet","title":"Done!",\n                   "message":"Your action was completed.","confirmLabel":"OK",\n                   "cancelLabel":"Cancel","showIcon":true }\n                 variant: success | info | error | warning\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nSCREEN PARAMETERS  (for dynamic/interactive screens)\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n"params": [\n  { "name":"activeTab", "type":"text",    "defaultValue":"home" },\n  { "name":"count",     "type":"number",  "defaultValue":"0"    },\n  { "name":"isOpen",    "type":"boolean", "defaultValue":"false" }\n]\nReference a param inside any text/color property with {{paramName}}.\nExample: "text": "Welcome, {{userName}}!"\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nTAP ACTIONS  (onTapActions array on any widget)\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n{ "type":"set",       "param":"tab",   "value":"home" }\n{ "type":"increment", "param":"count", "amount":1, "min":0, "max":99 }\n{ "type":"decrement", "param":"count", "amount":1, "min":0 }\n{ "type":"toggle",    "param":"isOpen","values":["false","true"] }\n{ "type":"multiply",  "param":"scale", "factor":2, "max":16 }\n{ "type":"if", "logic":"and",\n  "conditions":[{ "param":"tab","op":"==","value":"home" }],\n  "then":[{ "type":"set","param":"tab","value":"search" }],\n  "else":[{ "type":"set","param":"tab","value":"home" }]\n}\nOperators: == != > < >= <= contains !contains startsWith endsWith\nNavigation: set "navigateTo":"target_screen_id" in button properties, NOT in onTapActions.\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nWIDGET STATES  (conditional visual variants)\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n"states": {\n  "active": { "backgroundColor":"#2196F3","textColor":"#FFFFFF" },\n  "inactive": { "backgroundColor":"#F5F5F5","textColor":"#9E9E9E" }\n},\n"stateConditions": {\n  "active":   { "param":"activeTab","op":"==","value":"home" },\n  "inactive": { "param":"activeTab","op":"!=","value":"home" }\n}\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nLAYOUT PATTERNS \u2014 copy and adapt these\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\n\u2500\u2500 PATTERN 1: Scrollable page with AppBar + content \u2500\u2500\nScreen canvas: 390\xd7844. safeAreaTop:true, safeAreaBottom:true.\nWidget order by zIndex:\n  1. app_bar          x:0  y:0    w:390  h:56   (zIndex:10)\n  2. single_child_scroll_view  x:0  y:56  w:390  h:788  (zIndex:1) \u2190 takes remaining height\n  3. All content widgets have parentId \u2192 scroll_view\'s id, y starts at 0\n\n\u2500\u2500 PATTERN 2: Bottom navigation with tab switching \u2500\u2500\nParams: [{ "name":"tab","type":"text","defaultValue":"home" }]\n  1. bottom_nav_bar at y:794 (screen bottom 844 - 50)\n     Each nav item sets { "type":"set","param":"tab","value":"home" } via item0NavigateTo=tab action\n  2. Content containers use stateConditions to show/hide based on tab param:\n     "stateConditions": { "visible": { "param":"tab","op":"==","value":"home" } }\n     TRICK: Use a container with backgroundColor transparent when hidden, colored when visible.\n     Better: Use separate containers with opacity controlled via states.\n\n\u2500\u2500 PATTERN 3: Card list (static) \u2500\u2500\nUse a list_view container with fixedData JSON array.\nChildren widgets (text, image etc.) bind via _bindings to data fields.\nExample fixedData: "[{\\"name\\":\\"Item 1\\",\\"price\\":\\"$9.99\\"},{\\"name\\":\\"Item 2\\",\\"price\\":\\"$14.99\\"}]"\n\n\u2500\u2500 PATTERN 4: Interactive counter \u2500\u2500\nParams: [{ "name":"count","type":"number","defaultValue":"0" }]\nText widget: "text":"{{count}}"\nPlus button onTapActions:  [{ "type":"increment","param":"count","amount":1,"max":99 }]\nMinus button onTapActions: [{ "type":"decrement","param":"count","amount":1,"min":0 }]\n\n\u2500\u2500 PATTERN 5: Adaptive layout (mobile + tablet) \u2500\u2500\nwidgetsMobile: [ ...390px layout... ]\nwidgetsTablet: [ ...744px layout, usually 2-column grid or wider cards... ]\nwidgetsDesktop: [ ...1440px layout, sidebar + main content... ]\nEach list is COMPLETELY independent \u2014 duplicate and rearrange widgets.\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nCOMPLETE WORKING EXAMPLE  (simple dashboard \u2014 mobile only)\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n[\n  {\n    "id": "dashboard",\n    "name": "Dashboard",\n    "screenType": "screen",\n    "deviceMobile": "iphone16",\n    "backgroundColor": "#F5F7FA",\n    "safeAreaTop": true,\n    "safeAreaBottom": false,\n    "params": [{ "name":"tab","type":"text","defaultValue":"home" }],\n    "widgetsMobile": [\n      {\n        "id":"appbar","type":"app_bar","x":0,"y":0,"width":390,"height":56,"zIndex":10,\n        "parentId":null,"isFree":false,"constraintLeft":0,"constraintRight":0,"constraintTop":0,\n        "properties":{"title":"Dashboard","backgroundColor":"#FFFFFF","foregroundColor":"#1A1A1A","elevation":0,"centerTitle":false}\n      },\n      {\n        "id":"scroll","type":"single_child_scroll_view","x":0,"y":56,"width":390,"height":788,\n        "zIndex":1,"parentId":null,"isFree":false,\n        "constraintLeft":0,"constraintRight":0,"constraintTop":56,"constraintBottom":0,\n        "properties":{"scrollDirection":"vertical"}\n      },\n      {\n        "id":"greeting","type":"text","x":24,"y":16,"width":280,"height":null,\n        "zIndex":1,"parentId":"scroll","isFree":false,\n        "properties":{"text":"Good morning \ud83d\udc4b","fontSize":22,"fontWeight":"w700","color":"#1A1A1A","maxLines":1}\n      },\n      {\n        "id":"subtitle","type":"text","x":24,"y":48,"width":280,"height":null,\n        "zIndex":1,"parentId":"scroll","isFree":false,\n        "properties":{"text":"Here\'s your overview","fontSize":14,"fontWeight":"w400","color":"#757575","maxLines":1}\n      },\n      {\n        "id":"card1","type":"card","x":16,"y":90,"width":358,"height":120,\n        "zIndex":1,"parentId":"scroll","isFree":false,"wrapRadius":16,\n        "properties":{"backgroundColor":"#2196F3","borderRadius":16,"elevation":0}\n      },\n      {\n        "id":"card1_label","type":"text","x":20,"y":20,"width":200,"height":null,\n        "zIndex":2,"parentId":"card1","isFree":false,\n        "properties":{"text":"Total Revenue","fontSize":13,"fontWeight":"w500","color":"#FFFFFF","maxLines":1}\n      },\n      {\n        "id":"card1_value","type":"text","x":20,"y":44,"width":200,"height":null,\n        "zIndex":2,"parentId":"card1","isFree":false,\n        "properties":{"text":"$24,500","fontSize":28,"fontWeight":"w800","color":"#FFFFFF","maxLines":1}\n      },\n      {\n        "id":"card1_icon","type":"icon","x":300,"y":36,"width":40,"height":40,\n        "zIndex":2,"parentId":"card1","isFree":false,\n        "properties":{"icon":"trending_up","color":"#FFFFFF","size":32}\n      },\n      {\n        "id":"section_label","type":"text","x":16,"y":228,"width":200,"height":null,\n        "zIndex":1,"parentId":"scroll","isFree":false,\n        "properties":{"text":"Recent Activity","fontSize":16,"fontWeight":"w700","color":"#1A1A1A","maxLines":1}\n      },\n      {\n        "id":"list1","type":"list_tile","x":16,"y":264,"width":358,"height":64,\n        "zIndex":1,"parentId":"scroll","isFree":false,"wrapRadius":12,\n        "properties":{"title":"New order #1042","subtitle":"2 minutes ago","leadingIcon":"shopping_cart","trailingIcon":"chevron_right","titleColor":"#1A1A1A","subtitleColor":"#9E9E9E"}\n      },\n      {\n        "id":"list2","type":"list_tile","x":16,"y":340,"width":358,"height":64,\n        "zIndex":1,"parentId":"scroll","isFree":false,"wrapRadius":12,\n        "properties":{"title":"Payment received","subtitle":"1 hour ago","leadingIcon":"check","trailingIcon":"chevron_right","titleColor":"#1A1A1A","subtitleColor":"#9E9E9E"}\n      }\n    ],\n    "widgetsTablet": null,\n    "widgetsDesktop": null\n  }\n]\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nCOMMON MISTAKES TO AVOID\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\u2717 Forgetting to set parentId for nested widgets \u2192 widgets appear at wrong position\n\u2717 Using height:null on a container \u2192 containers need explicit height\n\u2717 Putting scrollable content WITHOUT a single_child_scroll_view parent \u2192 content clips\n\u2717 Placing widgets at y > screen height without a scroll container \u2192 they\'re invisible\n\u2717 Using same id for multiple widgets \u2192 causes rendering bugs\n\u2717 Omitting widgetsMobile key \u2192 screen appears empty\n\u2717 Referencing a navigateTo screen id that doesn\'t exist in the output array\n\u2717 For tab switching: DO NOT use separate screens \u2014 use params + stateConditions on containers\n\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nYOUR TASK\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\nGenerate the JSON for the following UI. Follow ALL rules above exactly.\nOutput ONLY the raw JSON array, nothing else.\n\nUser requirements:\n\n  "deviceMobile": "iphone16",   // iphone16|iphone16ProMax|iphone14|androidPhone\n  "backgroundColor": "#FFFFFF",\n  "safeAreaTop": false,\n  "safeAreaBottom": false,\n  "params": [],                 // screen-level parameters (see PARAMS section)\n  "widgetsMobile": [],          // array of widget objects\n  "widgetsTablet": null,        // optional tablet layout\n  "widgetsDesktop": null        // optional desktop layout\n}\n\n=== WIDGET STRUCTURE ===\n{\n  "id": "unique_id",\n  "type": "widget_type",\n  "x": 0, "y": 0,              // position relative to parent container (or screen)\n  "width": 390, "height": 60,  // height: null = auto/wrap-content\n  "zIndex": 0,\n  "parentId": null,             // set to parent container id when nested\n  "isFree": false,\n  "constraintLeft": 16,         // distance from left edge (null = not pinned)\n  "constraintRight": null,\n  "constraintTop": null,\n  "constraintBottom": 16,\n  "constraintCenterX": false,\n  "constraintCenterY": false,\n  "widthPct": null,             // width as % of parent (overrides width when set)\n  "heightPct": null,\n  "padding": 0,\n  "wrapRadius": 0,              // clip+border radius applied outside the widget\n  "wrapBorderWidth": 0,\n  "wrapBorderColor": "#000000",\n  "name": "",                   // optional identifier\n  "properties": { ... },        // widget-specific props (see WIDGET TYPES)\n  "states": {},                 // named visual states\n  "stateConditions": {},        // auto-activate state based on param value\n  "onTapActions": [],           // actions fired on tap (see ACTIONS)\n  "isSelected": false,\n  "isDragging": false\n}\n\n=== WIDGET TYPES & PROPERTIES ===\n\ncontainer:\n  { "backgroundColor": "#FFFFFF", "borderRadius": 12, "shadowBlur": 8, "shadowColor": "#00000020",\n    "borderWidth": 0, "borderColor": "#000000" }\n\ntext:\n  { "text": "Hello World", "fontSize": 16, "fontWeight": "w600",\n    "color": "#000000", "textAlign": "left", "maxLines": 0 }\n\nelevated_button / text_button / outlined_button:\n  { "label": "Button", "backgroundColor": "#2196F3", "textColor": "#FFFFFF",\n    "borderRadius": 8, "fontSize": 14, "fontWeight": "w600",\n    "navigateTo": "screen_id", "isClickable": true }\n\ntext_field:\n  { "hint": "Enter text", "label": "Field Label", "fillColor": "#F5F5F5",\n    "borderRadius": 8, "keyboardType": "text", "name": "field_name",\n    "textColor": "#000000", "hintColor": "#9E9E9E" }\n\nimage:\n  { "url": "https://...", "fit": "cover", "borderRadius": 0 }\n\nicon:\n  { "icon": "home", "color": "#000000", "size": 24 }\n\nswitch:\n  { "value": false, "activeColor": "#2196F3" }\n\ncheckbox:\n  { "value": false, "activeColor": "#2196F3", "label": "" }\n\nslider:\n  { "value": 0.5, "min": 0, "max": 1, "activeColor": "#2196F3",\n    "inactiveColor": "#E0E0E0" }\n\ncircle_avatar:\n  { "url": "", "initials": "AB", "backgroundColor": "#E0E0E0",\n    "textColor": "#000000", "size": 48 }\n\nchip:\n  { "label": "Tag", "backgroundColor": "#E0E0E0", "textColor": "#000000",\n    "borderRadius": 20, "fontSize": 12 }\n\ncard:\n  { "backgroundColor": "#FFFFFF", "borderRadius": 12, "elevation": 2,\n    "shadowColor": "#00000020" }\n\nlist_tile:\n  { "title": "Title", "subtitle": "", "leadingIcon": "person",\n    "trailingIcon": "chevron_right", "titleColor": "#000000", "subtitleColor": "#757575" }\n\ndivider:\n  { "thickness": 1, "color": "#E0E0E0", "indent": 0, "endIndent": 0 }\n\napp_bar:\n  { "title": "Screen Title", "backgroundColor": "#2196F3",\n    "foregroundColor": "#FFFFFF", "elevation": 0, "centerTitle": true }\n\nbottom_nav_bar:\n  { "item0Label": "Home", "item0Icon": "home", "item0NavigateTo": "screen_id",\n    "item1Label": "Search", "item1Icon": "search", "item1NavigateTo": "",\n    "item2Label": "Profile", "item2Icon": "person", "item2NavigateTo": "",\n    "currentIndex": 0, "backgroundColor": "#FFFFFF",\n    "selectedColor": "#2196F3", "unselectedColor": "#757575" }\n\nfab:\n  { "icon": "add", "backgroundColor": "#2196F3", "foregroundColor": "#FFFFFF",\n    "label": "", "navigateTo": "" }\n\ncircular_progress / linear_progress:\n  { "value": 0.5, "color": "#2196F3", "backgroundColor": "#E0E0E0" }\n\nlist_view (CONTAINER \u2014 add children with parentId):\n  { "dataSource": "fixed",\n    "fixedData": "[{\\"id\\":1,\\"name\\":\\"Item 1\\"}]",\n    "itemHeight": 80, "itemSpacing": 8, "scrollDirection": "vertical",\n    "showScrollbar": false,\n    "paddingLeft": 0, "paddingTop": 0, "paddingRight": 0, "paddingBottom": 0 }\n\ngrid_view (CONTAINER):\n  { "dataSource": "fixed", "fixedData": "[]",\n    "crossAxisCount": 2, "childAspectRatio": 1.0,\n    "mainAxisSpacing": 8, "crossAxisSpacing": 8 }\n\nrow / column (CONTAINER):\n  { "mainAxisAlignment": "start", "crossAxisAlignment": "center" }\n\nsingle_child_scroll_view (CONTAINER):\n  { "scrollDirection": "vertical" }\n\npage_view / tab_bar_view (CONTAINER): {}\n\nsubmit_button:\n  { "label": "Submit", "backgroundColor": "#2196F3", "textColor": "#FFFFFF",\n    "borderRadius": 8 }\n\n=== SCREEN PARAMS ===\nDeclared at screen level; referenced in any widget property as {{paramName}}.\n"params": [\n  { "name": "userName", "type": "text", "defaultValue": "Guest" },\n  { "name": "count",    "type": "number", "defaultValue": "0" },\n  { "name": "isActive", "type": "boolean", "defaultValue": "false" }\n]\n\n=== ACTIONS (onTapActions) ===\n[\n  { "type": "set",       "param": "tab",   "value": "home" },\n  { "type": "increment", "param": "count", "amount": 1, "min": 0, "max": 99 },\n  { "type": "decrement", "param": "count", "amount": 1, "min": 0 },\n  { "type": "toggle",    "param": "open",  "values": ["false","true"] },\n  { "type": "multiply",  "param": "scale", "factor": 2, "max": 8 },\n  {\n    "type": "if", "logic": "and",\n    "conditions": [{ "param": "tab", "op": "==", "value": "home" }],\n    "then": [{ "type": "set", "param": "tab", "value": "search" }],\n    "else": [{ "type": "set", "param": "tab", "value": "home" }]\n  }\n]\nOperators: == != > < >= <= contains !contains startsWith endsWith\n\n=== WIDGET STATES ===\n"states": {\n  "active": { "backgroundColor": "#2196F3", "textColor": "#FFFFFF" }\n},\n"stateConditions": {\n  "active": { "param": "activeTab", "op": "==", "value": "home" }\n}\n\n=== NESTING ===\nNest a widget inside a container by setting its parentId to the container\'s id.\nChild x/y are relative to the parent container, not the screen.\n\n=== NAVIGATION ===\nSet "navigateTo": "target_screen_id" in button/fab properties.\nScreens with screenType "bottomSheet" appear as a modal bottom sheet.\nScreens with screenType "dialog" appear as an alert dialog.\nScreens with screenType "customView" can be embedded in other screens.\n\n=== CONSTRAINTS ===\nUse constraintLeft/Right/Top/Bottom (px) to pin edges.\nUse constraintCenterX/Y: true to center on that axis.\nSetting both Left+Right makes the widget stretch horizontally.\nwidthPct/heightPct override absolute width/height with a % of parent size.\n\n---\nWrite JSON for the following screens (describe your requirements below):\n')
